#include<bits/stdc++.h>
using namespace std;
const int N=10;
int nu[N],n,k,cnt;
void dfs(int num,int sum)
{
    if(num>k)
    {
        if(sum==0) cnt++;
        return ;
    }
    for(int i=1;i<=sum;i++)
    {
        if(i>nu[num-1]) break;
        nu[num]=i;
        dfs(num+1,sum-i);
    }

}
int main()
{
    cin>>n>>k;
    nu[0]=205;
    dfs(1,n);
    cout<<cnt;
    return 0;
}
